import{_ as g,o as C,c as s,a0 as a}from"./chunks/framework.RL10UjUE.js";const B="/bookmark-manager-pe/assets/setup.ZFXwsu-i.png",t="data:image/png;base64,",i=JSON.parse('{"title":"GitHub 同期","description":"","frontmatter":{},"headers":[],"relativePath":"guide/sync.md","filePath":"guide/sync.md"}'),e={name:"guide/sync.md"};function E(r,A,n,I,Q,l){return C(),s("div",null,[...A[0]||(A[0]=[a('<h1 id="github-同期" tabindex="-1">GitHub 同期 <a class="header-anchor" href="#github-同期" aria-label="Permalink to &quot;GitHub 同期&quot;">​</a></h1><p>GitHub リポジトリを介して、複数のデバイス間でブックマークを同期できます。各デバイスごとに個別の JSON ファイルが保存され、デバイス間の差分はコンフリクト解決 UI で安全にマージできます。</p><h2 id="セットアップ" tabindex="-1">セットアップ <a class="header-anchor" href="#セットアップ" aria-label="Permalink to &quot;セットアップ&quot;">​</a></h2><h3 id="_1-github-personal-access-token-の発行" tabindex="-1">1. GitHub Personal Access Token の発行 <a class="header-anchor" href="#_1-github-personal-access-token-の発行" aria-label="Permalink to &quot;1. GitHub Personal Access Token の発行&quot;">​</a></h3><ol><li>GitHub にログイン → Settings → Developer settings → Personal access tokens → Tokens (classic)</li><li><strong>Generate new token (classic)</strong> をクリック</li><li>スコープで <strong><code>repo</code></strong> にチェック（フルコントロール）</li><li>任意のメモ（例: &quot;Bookmark Manager PE&quot;）を入力</li><li>生成されたトークンをコピー（<code>ghp_xxxxx</code>）</li></ol><p>![トークン発行画面（GitHub）]</p><h3 id="_2-同期リポジトリの準備" tabindex="-1">2. 同期リポジトリの準備 <a class="header-anchor" href="#_2-同期リポジトリの準備" aria-label="Permalink to &quot;2. 同期リポジトリの準備&quot;">​</a></h3><p>同期用の GitHub リポジトリを新規作成してください（公開・非公開どちらでも可）。リポジトリの中身は自動的に管理されます。</p><h3 id="_3-アプリで設定" tabindex="-1">3. アプリで設定 <a class="header-anchor" href="#_3-アプリで設定" aria-label="Permalink to &quot;3. アプリで設定&quot;">​</a></h3><ol><li>サイドバー下部の <strong>同期</strong> ボタンをクリック</li><li>表示されたダイアログに以下の項目を入力: <ul><li><strong>Personal Access Token</strong>: 先ほど発行したトークン</li><li><strong>リポジトリ所有者</strong>: ユーザー名または Organization 名</li><li><strong>リポジトリ名</strong>: 作成したリポジトリ名</li><li><strong>デバイス名</strong>: このデバイスの識別名（例: &quot;MacBook Air&quot;）</li></ul></li></ol><p><img src="'+B+'" alt="同期設定ダイアログ"></p><ol start="3"><li><strong>接続テスト＆保存</strong> をクリック</li><li>接続成功すると、サイドバーにグリーンのクラウドアイコンが表示されます</li></ol><h2 id="同期の実行" tabindex="-1">同期の実行 <a class="header-anchor" href="#同期の実行" aria-label="Permalink to &quot;同期の実行&quot;">​</a></h2><p>サイドバーの <strong>同期</strong> ボタンをクリックすると、以下の流れで同期が実行されます。</p><ol><li>GitHub から他デバイスのブックマークファイルを取得</li><li>ローカルのブックマークとマージ</li><li>自分のデバイスのブックマークを GitHub にプッシュ</li><li>結果を通知（何件取り込んだか、何件送信したか）</li></ol><h2 id="コンフリクト解決" tabindex="-1">コンフリクト解決 <a class="header-anchor" href="#コンフリクト解決" aria-label="Permalink to &quot;コンフリクト解決&quot;">​</a></h2><p>同じブックマークが複数のデバイスで別々に更新されていた場合、コンフリクト解決モーダルが表示されます。</p><p><img src="'+t+`" alt="コンフリクト解決モーダル"></p><p>各コンフリクトごとに以下の選択肢があります。</p><table tabindex="0"><thead><tr><th>選択肢</th><th>動作</th></tr></thead><tbody><tr><td>ローカルを保持</td><td>このデバイスの内容を残す</td></tr><tr><td>リモートを採用</td><td>GitHub 上の内容で上書き</td></tr><tr><td>自動マージ</td><td>タイトル・タグ・メモを統合</td></tr><tr><td>スキップ</td><td>今回は判断せず、後で再度同期</td></tr></tbody></table><p>すべてのコンフリクトを解決したら <strong>完了</strong> をクリックします。</p><h2 id="データの保存形式" tabindex="-1">データの保存形式 <a class="header-anchor" href="#データの保存形式" aria-label="Permalink to &quot;データの保存形式&quot;">​</a></h2><p>リポジトリ内のファイル構造:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>リポジトリ/</span></span>
<span class="line"><span>├── bookmarks/</span></span>
<span class="line"><span>│   ├── device-{id1}.json    # デバイス A のブックマーク</span></span>
<span class="line"><span>│   └── device-{id2}.json    # デバイス B のブックマーク</span></span>
<span class="line"><span>├── metadata/</span></span>
<span class="line"><span>│   ├── devices.json         # 登録デバイス一覧</span></span>
<span class="line"><span>│   └── sync-state.json      # 同期状態</span></span></code></pre></div><p>各デバイスのデータは独立したファイルとして保存されるため、あるデバイスで障害が起きても他のデバイスに影響しません。</p>`,25)])])}const w=g(e,[["render",E]]);export{i as __pageData,w as default};
